'use client'

import { useState, useEffect } from 'react'
import { Star, ThumbsUp, MessageCircle, Calendar } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'
import { Progress } from '@/components/ui/progress'
import { cn } from '@/lib/utils'
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselPrevious,
  CarouselNext,
  type CarouselApi,
} from '@/components/ui/carousel'

interface Review {
  id: number
  userName: string
  userAvatar: string
  date: string
  rating: number
  content: string
  likes: number
  comments: number
}

interface StoreData {
  pageTitle: string
  pageDescription: string
  averageRating: number
  totalReviews: number
  ratingDistribution: Record<string, number>
  reviews: Review[]
}

const storeData: StoreData = {
  pageTitle: 'Customer Stories',
  pageDescription: 'Discover what our community has to say about their experience. Real stories from real users.',
  averageRating: 4.8,
  totalReviews: 1482,
  ratingDistribution: { '5': 75, '4': 20, '3': 5, '2': 5, '1': 5 },
  reviews: [
    {
      id: 1,
      userName: 'Emma Davis',
      userAvatar: 'https://notion-avatars.netlify.app/api/avatar?preset=female-1',
      date: '20 Mar, 2024',
      rating: 5,
      content:
        "The quality of this product is outstanding! It arrived well-packaged and exceeded my expectations. The materials are durable and the design is both functional and stylish. I've received so many compliments already!",
      likes: 28,
      comments: 12,
    },
    {
      id: 2,
      userName: 'Alex Morgan',
      userAvatar: 'https://notion-avatars.netlify.app/api/avatar?preset=male-1',
      date: '18 Mar, 2024',
      rating: 4,
      content:
        "I was a bit hesitant about the price at first, but after using it for a week, I can confidently say it's worth every penny. The only improvement I can think of would be to include more color options. Highly recommend!",
      likes: 15,
      comments: 3,
    },
    {
      id: 3,
      userName: 'Sarah Chen',
      userAvatar: 'https://notion-avatars.netlify.app/api/avatar?preset=male-3',
      date: '15 Mar, 2024',
      rating: 5,
      content:
        "This product has made such a difference in my daily routine. It's easy to use, reliable, and looks great in my home. The customer service was also excellent when I had a question about the settings.",
      likes: 42,
      comments: 8,
    },
  ],
}

const ReviewRating3 = () => {
  const [carouselApi, setCarouselApi] = useState<CarouselApi>()
  const [current, setCurrent] = useState<number>(0)
  const [isLiked, setIsLiked] = useState<Record<number, boolean>>({})

  useEffect(() => {
    if (!carouselApi) return

    const updateCurrent = () => setCurrent(carouselApi.selectedScrollSnap())

    carouselApi.on('select', updateCurrent)
    return () => {
      carouselApi.off('select', updateCurrent)
    }
  }, [carouselApi])

  const scrollTo = (index: number) => {
    if (carouselApi) {
      carouselApi.scrollTo(index)
    }
  }

  const handleLike = (reviewId: number) => {
    setIsLiked(prev => ({
      ...prev,
      [reviewId]: !prev[reviewId],
    }))
  }

  const formatNumber = (num: number): string => {
    return num >= 1000 ? `${(num / 1000).toFixed(1)}k` : num.toString()
  }

  return (
    <div className='mx-auto w-full max-w-7xl px-4 sm:px-6 lg:px-8 py-12'>
      <div className='mb-12 text-center'>
        <h2 className='mb-3 text-4xl font-bold'>{storeData.pageTitle}</h2>
        <p className='text-muted-foreground mx-auto max-w-2xl'>{storeData.pageDescription}</p>
      </div>

      <div className='mt-8 mb-12 flex flex-col items-center justify-center gap-8 md:flex-row'>
        <div className='text-center'>
          <div className='mb-2 text-6xl font-bold'>{storeData.averageRating}</div>
          <div className='flex justify-center gap-1'>
            {Array.from({ length: 5 }).map((_, i) => (
              <Star key={i} className={cn('size-5', 'fill-current')} />
            ))}
          </div>
          <p className='text-muted-foreground mt-1 text-sm'>Based on {formatNumber(storeData.totalReviews)} reviews</p>
        </div>

        <div className='bg-border mx-4 hidden h-16 w-px md:block' />

        <div className='flex flex-col gap-1'>
          {Object.entries(storeData.ratingDistribution).map(([rating, percentage]) => (
            <div key={rating} className='flex items-center gap-2'>
              <div className='flex flex-1 justify-end gap-1'>
                {Array.from({ length: Number(rating) }).map((_, i) => (
                  <Star key={i} className='size-3 fill-current' />
                ))}
              </div>
              <Progress value={percentage} className='h-2 w-32' />
              <span className='text-muted-foreground w-8 text-sm'>{percentage}%</span>
            </div>
          ))}
        </div>
      </div>

      {/* Carousel Section */}
      <div className='relative mx-auto max-w-4xl'>
        <Carousel
          setApi={setCarouselApi}
          className='w-full'
          opts={{
            align: 'start',
            loop: true,
          }}
        >
          <CarouselContent>
            {storeData.reviews.map(review => (
              <CarouselItem key={review.id}>
                <div className='p-6 sm:p-8'>
                  <div className='flex flex-col gap-4'>
                    {/* First Row: User Info */}
                    <div className='flex items-start gap-4'>
                      <Avatar className='bg-muted size-12'>
                        <AvatarImage src={review.userAvatar} alt={review.userName} />
                        <AvatarFallback>{review.userName.substring(0, 2)}</AvatarFallback>
                      </Avatar>
                      <div className='flex-1'>
                        <h3 className='text-lg font-semibold'>{review.userName}</h3>
                        <div className='mt-1 flex items-center gap-2'>
                          <div className='flex gap-0.5'>
                            {Array.from({ length: review.rating }).map((_, i) => (
                              <Star key={i} className='size-4 fill-current' />
                            ))}
                          </div>
                          <span className='text-muted-foreground text-sm'>•</span>
                          <time className='text-muted-foreground flex items-center text-sm'>
                            <Calendar className='me-1 size-3.5' />
                            {review.date}
                          </time>
                        </div>
                      </div>
                    </div>

                    {/* Second Row: Review Content and Actions */}
                    <div>
                      <p className='text-muted-foreground'>{review.content}</p>
                      <div className='mt-4 flex gap-4'>
                        <Button
                          variant='ghost'
                          size='sm'
                          onClick={() => handleLike(review.id)}
                          className="h-8 px-3 text-xs text-muted-foreground hover:bg-primary/10 hover:text-primary cursor-pointer"
                        >
                          <ThumbsUp className={cn('size-4', isLiked[review.id] && 'fill-current')} />
                          {formatNumber(review.likes + (isLiked[review.id] ? 1 : 0))}
                        </Button>
                        <Button
                          variant='ghost'
                          size='sm'
                          className="h-8 px-3 text-xs text-muted-foreground hover:bg-primary/10 hover:text-primary cursor-pointer"
                        >
                          <MessageCircle className='size-4' />
                          {formatNumber(review.comments)}
                        </Button>
                      </div>
                    </div>
                  </div>
                </div>
              </CarouselItem>
            ))}
          </CarouselContent>
          <CarouselPrevious />
          <CarouselNext />
        </Carousel>

        {/* Carousel Indicators */}
        <div className='flex justify-center gap-2'>
          {storeData.reviews.map((_, i) => (
            <Button
              key={i}
              onClick={() => scrollTo(i)}
              className={`mx-1 size-2 cursor-pointer rounded-full p-1 transition-all ${current === i ? 'bg-foreground w-6' : 'bg-muted'}`}
              aria-label={`Go to review ${i + 1}`}
              aria-current={current === i ? 'step' : undefined}
            />
          ))}
        </div>
      </div>
    </div>
  )
}

export default ReviewRating3
